generated_oml:
// Sensing Components
instance MotorEncoderComponent : DTDFVocab:SensingComponent [
    base:desc "High‑precision encoder mounted on the motor shaft, measuring motor rotational position."
    DTDFVocab:producedData MotorJointAngleDataTransmitted
]

instance GearboxEncoderComponent : DTDFVocab:SensingComponent [
    base:desc "High‑precision encoder attached to the gearbox output, measuring joint rotational position."
    DTDFVocab:producedData GearboxJointAngleDataTransmitted
]

instance MotorCurrentSensorComponent : DTDFVocab:SensingComponent [
    base:desc "Current sensor on the motor phase, measuring electrical current supplied to the motor."
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

// Data Transmitted
instance MotorJointAngleDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoderComponent
]

instance GearboxJointAngleDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoderComponent
]

instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensorComponent
]

instance CombinedMeasurementsDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoderComponent, GearboxEncoderComponent, MotorCurrentSensorComponent
]

// Derived Data
instance MeasuredTorqueData : DTDFVocab:Data [
    base:desc "Torque derived from measured motor current and joint positions."
    DTDFVocab:fromData CombinedMeasurementsDataTransmitted
    DTDFVocab:inputTo DataProcessingEngine
]

instance MeasuredAngularVelocityData : DTDFVocab:Data [
    base:desc "Angular velocity computed from joint position over time."
    DTDFVocab:fromData CombinedMeasurementsDataTransmitted
    DTDFVocab:inputTo DataProcessingEngine
]

instance MeasuredAccelerationData : DTDFVocab:Data [
    base:desc "Angular acceleration derived from angular velocity."
    DTDFVocab:fromData CombinedMeasurementsDataTransmitted
    DTDFVocab:inputTo DataProcessingEngine
]

instance SimulatedTorqueData : DTDFVocab:Data [
    base:desc "Torque simulated by the Simulink model incorporating identified friction models."
    DTDFVocab:fromData CombinedMeasurementsDataTransmitted
    DTDFVocab:inputTo SimulationEngine
]

instance SimulatedAngularVelocityData : DTDFVocab:Data [
    base:desc "Angular velocity simulated by the Simulink model."
    DTDFVocab:fromData CombinedMeasurementsDataTransmitted
    DTDFVocab:inputTo SimulationEngine
]

instance SimulatedAccelerationData : DTDFVocab:Data [
    base:desc "Angular acceleration simulated by the Simulink model."
    DTDFVocab:fromData CombinedMeasurementsDataTransmitted
    DTDFVocab:inputTo SimulationEngine
]

// Enablers
instance MQTTBroker : DTDFVocab:Enabler [
    base:desc "MQTT broker handling real‑time sensor data streams into the digital twin."
    DTDFVocab:enables DashboardEngine, LiveDashboardService
]

instance SimulationEngine : DTDFVocab:Enabler [
    base:desc "Execution engine running Simulink models for joint dynamics and friction."
    DTDFVocab:enables FrictionIdentificationService
]

instance DataProcessingEngine : DTDFVocab:Enabler [
    base:desc "Processing component orchestrating data calculation and transformation from raw measurements."
    DTDFVocab:enables ControllerUpdateService
]

instance DashboardEngine : DTDFVocab:Enabler [
    base:desc "Web‑based visualization engine rendering live dashboards."
    DTDFVocab:enables LiveDashboardService
]

// Services
instance LiveDashboardService : DTDFVocab:Service [
    base:desc "Live dashboard service visualizing current and simulated joint signals via a web interface."
    DTDFVocab:provides DashboardVisualizationInsight
]

instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Service performing continuous multi‑physics friction identification using white‑box and black‑box models."
    DTDFVocab:provides UpdatedFrictionModelInsight, UpdateControllerParametersAction
]

instance ControllerUpdateService : DTDFVocab:Service [
    base:desc "Service applying updated control parameters to the robot controller."
    DTDFVocab:provides ApplyNewControllerSettingsAction
]

// Models
instance EngineeringModel : DTDFVocab:Model [
    base:desc "SysML engineering model of the motor and gearbox components and their connectors."
]

instance SimulinkModel : DTDFVocab:Model [
    base:desc "Simulink block diagram representing motor, gearwheel, and gearbox dynamics with friction models (Coulomb, viscous, Stribeck, Dahl, LuGre)."
    DTDFVocab:inputTo SimulationEngine
]

// Insights
instance DashboardVisualizationInsight : DTDFVocab:Insight [
    base:desc "Real‑time visualization of measured and simulated joint signals on the web dashboard."
]

instance UpdatedFrictionModelInsight : DTDFVocab:Insight [
    base:desc "Updated friction model parameters (Coulomb, viscous, Stribeck, Dahl, LuGre) derived from continuous identification."
]

// Actions
instance UpdateControllerParametersAction : DTDFVocab:Action [
    base:desc "Automatic update of robot controller parameters using newly identified friction coefficients."
    DTDFVocab:IsAutomatic true
]

instance ApplyNewControllerSettingsAction : DTDFVocab:Action [
    base:desc "Applying the updated control settings to the robot for improved accuracy."
    DTDFVocab:IsAutomatic true
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "None – the digital shadow does not send commands back to the PT."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "The DT operates in real‑time, processing sensor streams and simulation outputs synchronously with the robot’s motion, ensuring that data points are generated and available on the same timescale as the physical operations."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "Asset (first axis) → Engineering model (SysML) → Simulation models (Simulink) → Processing component (data calculation & simulation) → Data traces (measured and simulated) → Dashboard UI; all connected via MQTT and AAS."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The DT covers: (1) Design – ideal, frictionless simulation models of motor and gearbox; (2) Operation – live data collection and continuous identification of friction; (3) Calibration – parameter adjustment based on comparison between measured and simulated signals."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "High‑resolution encoders provide accurate joint state measurements; simulation models are white‑box analytical and black‑box data‑driven, allowing cross‑validation; traceability of each data point back to its source (sensor or processing component) enables verification; ongoing comparison of measured vs simulated trajectories ensures validity of the digital twin."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Sensor data are transmitted from the PT to the DT over MQTT (likely over TCP/IP), with each MQTT topic corresponding to a data trace; the processing component subscribes to topics and feeds simulation models; the dashboard connects to the processing component via a web socket for real‑time visualization."
]

instance dt_hosting_deployment : DTDFVocab:Deployment [
    base:desc "The digital shadow runs on a local server or embedded computer within the robot’s safety cell; the visualization dashboard is served from the same host and accessed through an internal web interface."
]

instance data_ownership_and_privacy : DTDFVocab:DataOwnershipPrivacy [
    base:desc "Data collected by the robot reside with the PT owner (robot manufacturer/operator); the digital shadow does not alter ownership and complies with the PT owner’s data policy."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Use of SysML for MBSE (ISO/IEC 19650‑4), Asset Administration Shells (IEC 61360/Siemens), and standard friction models (Coulomb‑Viscous, Stribeck, Dahl, LuGre) adheres to common industry standards."
]

instance security_and_safety_considerations : DTDFVocab:SecuritySafety [
    base:desc "The digital shadow is passive and does not command the PT; sensor data are transmitted over MQTT which may be secured with TLS; no remote actuation reduces safety risk; secure authentication is recommended for data integrity."
]
